use std::collections::HashMap;
use std::sync::Arc;

struct ScannerSettings {
    timeout_ms: u32,
    user_agent: String,
}

fn process_packet(settings: Arc<ScannerSettings>, host: &str) -> Result<(), String> {
    if settings.timeout_ms == 0 {
        return Err("Timeout is zero, cannot scan".to_string());
    }
    println!("Scanning {} with agent: {}", host, &settings.user_agent);
    Ok(())
}

fn main() -> Result<(), String> {
    let base_settings = ScannerSettings {
        timeout_ms: 2000,
        user_agent: "CustomPortScanner/1.0".to_string(),
    };

    let shared_settings = Arc::new(base_settings);

    let hosts_to_scan = vec!["192.168.1.1", "127.0.0.1"];

    for host in hosts_to_scan {
        let settings_clone = Arc::clone(&shared_settings);
        if let Err(e) = process_packet(settings_clone, host) {
            eprintln!("Error processing {}: {}", host, e);
        }
    }

    Ok(())
}
